CREATE TABLE `edihead`
(
    `ID`      int(11)              NOT NULL AUTO_INCREMENT,
    `id_kola` int(11)                       DEFAULT 0,
    `TDate`   varchar(17)          NOT NULL,
    `PCall`   varchar(30)          NOT NULL,
    `PWWLo`   varchar(6)           NOT NULL,
    `PSect`   varchar(20)          NOT NULL DEFAULT '',
    `PBand`   varchar(20)          NOT NULL DEFAULT '',
    `RName`   varchar(50)          NOT NULL,
    `REmai`   varchar(100)                  DEFAULT NULL,
    `RPhon`   varchar(50)          NOT NULL DEFAULT '',
    `RHBBS`   varchar(50)          NOT NULL,
    `SPowe`   smallint(5) unsigned NOT NULL,
    `STXEq`   varchar(100)                  DEFAULT NULL,
    `SAnte`   varchar(100)                  DEFAULT NULL,
    `src`     mediumtext                    DEFAULT NULL,
    `Remarks` text                          DEFAULT NULL,
    `stamp`   timestamp            NOT NULL DEFAULT current_timestamp(),
    `d_cas`   timestamp            NULL     DEFAULT current_timestamp(),
    `SRCR`    longtext                      DEFAULT NULL,
    PRIMARY KEY (`ID`),
    KEY `id_kola` (`id_kola`)
) ENGINE = InnoDB
  AUTO_INCREMENT = 23111
  DEFAULT CHARSET = utf8mb4
  COLLATE = utf8mb4_unicode_ci;


